patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..d555a558b557 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4509,6 +4509,7 @@ static Instruction *foldICmpOrXX(ICmpInst &I, const SimplifyQuery &Q,

 static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
                                   InstCombinerImpl &IC) {
+  errs() << "foldICmpXorXX: " << I << "\n";
   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *A;
   // Normalize xor operand as operand 0.
   CmpInst::Predicate Pred = I.getPredicate();
@@ -4528,6 +4529,18 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
     return new ICmpInst(PredOut, Op0, Op1);

+  // Transform icmp lt/le/gt/ge (X ^ Y), X where X = ~a to
+  // icmp swapped_predicate (Y ^ a), a.
+  // This eliminates the not operation.
+  Value *InnerA;
+  if (match(Op1, m_c_Xor(m_Value(InnerA), m_AllOnes()))) {
+    // Op0 = (InnerA ^ -1) ^ Y, where Y = A (already captured).
+    // We can replace with (Y ^ InnerA) swapped_predicate InnerA.
+    CmpInst::Predicate NewPred = ICmpInst::getSwappedPredicate(Pred);
+    Value *NewXor = IC.Builder.CreateXor(A, InnerA);
+    return new ICmpInst(NewPred, NewXor, InnerA);
+  }
+
   return nullptr;
 }

